//! Auto-generated by the spec-word-compliance workflow.
//!
//! Area: "Style inheritance via basedOn (build-up, conflict override, cycles)".
//!
//! Each `#[test]` encodes a Word-consumption / validity constraint for the
//! `w:basedOn` style-inheritance rules of ECMA-376 / ISO 29500 §17.7 and the
//! Microsoft implementer notes MS-OI29500 §2.1.233. A FAILING assertion here
//! encodes a REAL Word-compliance gap in the stemma engine: stemma diverges
//! from what real Microsoft Word does when consuming the markup. A fail is a
//! finding to investigate at the source, NOT something to weaken the test for.
//!
//! Methodology note: every expectation below is on the READ side
//! (`read_accepted`/`read_rejected().to_text()`) or on `stemma::api::validate`
//! (opens-clean). None assert on re-serialized XML, because stemma round-trips
//! untouched content byte-verbatim, so re-serialized XML would reflect the
//! verbatim-preservation contract, not Word's consumption/normalization.

use stemma::api::Document;

// ─── Prelude: minimal .docx plumbing (mirrors the shared spec-suite prelude
//     `make_test_docx` + tests/common/mod.rs zip plumbing) ──────────────────

/// Build a valid minimal `.docx`. `body_xml` is wrapped in
/// `<w:document><w:body>…</w:body></w:document>`. `extra_parts` is a list of
/// `(part_name, xml)` — e.g. `("word/styles.xml", "<?xml …><w:styles…>")`.
/// Content-type overrides + the document rels for known parts are added so the
/// package is well-formed for stemma to parse and for Word to open.
fn make_docx(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:body>{body_xml}</w:body></w:document>"#
    );

    // Content-type overrides + document.xml.rels relationships for each known
    // extra part. We fail loud on an unknown part rather than silently emitting
    // a package Word would reject (CLAUDE.md — no silent fallbacks).
    let mut overrides = String::new();
    let mut doc_rel_entries = String::new();
    for (rel_seq, (part, _)) in (100u32..).zip(extra_parts.iter()) {
        match *part {
            "word/styles.xml" => {
                overrides.push_str(
                    r#"<Override PartName="/word/styles.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"/>"#,
                );
                doc_rel_entries.push_str(&format!(
                    r#"<Relationship Id="rId{rel_seq}" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/styles" Target="styles.xml"/>"#
                ));
            }
            "word/numbering.xml" => {
                overrides.push_str(
                    r#"<Override PartName="/word/numbering.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml"/>"#,
                );
                doc_rel_entries.push_str(&format!(
                    r#"<Relationship Id="rId{rel_seq}" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/numbering" Target="numbering.xml"/>"#
                ));
            }
            other => panic!(
                "make_docx: unknown extra part {other:?} — add its content-type override + rel mapping"
            ),
        }
    }

    let content_types = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/><Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>{overrides}</Types>"#
    );
    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#;
    let doc_rels = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">{doc_rel_entries}</Relationships>"#
    );

    use std::io::Write;
    use zip::write::FileOptions;
    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(std::io::Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (part, xml) in extra_parts {
            zip.start_file(*part, opts).unwrap();
            zip.write_all(xml.as_bytes()).unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

/// Unzip `docx` and return `word/document.xml` as a String.
#[allow(dead_code)]
fn document_xml_of(docx: &[u8]) -> String {
    let archive = stemma::docx::DocxArchive::read(docx).expect("read docx archive");
    String::from_utf8_lossy(
        archive
            .get("word/document.xml")
            .expect("document.xml present"),
    )
    .into_owned()
}

/// Parse `bytes`, re-serialize with default export options, and return the
/// resulting `word/document.xml`.
#[allow(dead_code)]
fn reserialize(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse for reserialize");
    let out = doc
        .serialize(&stemma::ExportOptions::default())
        .expect("serialize");
    document_xml_of(&out)
}

/// Assert `stemma::api::validate(bytes)` reports no errors, with a rule-bearing
/// message on failure.
fn assert_opens_clean(bytes: &[u8], msg: &str) {
    let report = stemma::api::validate(bytes);
    assert!(
        report.ok,
        "{msg} — validate reported issues: {:?}",
        report.issues
    );
}

