#[test]
fn basedon_cycle_opens_clean_and_body_survives() {
    let styles = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><w:styles xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:style w:type="paragraph" w:styleId="CycleA"><w:name w:val="CycleA"/><w:basedOn w:val="CycleB"/><w:pPr><w:jc w:val="center"/></w:pPr></w:style><w:style w:type="paragraph" w:styleId="CycleB"><w:name w:val="CycleB"/><w:basedOn w:val="CycleA"/><w:rPr><w:b/></w:rPr></w:style></w:styles>"#;
    let body = r#"<w:p><w:pPr><w:pStyle w:val="CycleA"/></w:pPr><w:r><w:t>cycle body text</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[("word/styles.xml", styles)]);

    assert_opens_clean(
        &b,
        "Word requires the based-on chain to have no circular reference (MS-OI29500 §2.1.233); a headless-Word engine must terminate the cyclic walk and emit a document that opens without repair. refs: MS-OI29500 §2.1.233, ISO 29500-1 §17.7.4.3, ISO 29500-1 §17.7.1",
    );

    let doc = Document::parse(&b).expect("parse");
    assert_eq!(
        doc.read_rejected().unwrap().to_text().trim(),
        "cycle body text",
        "The standard allows loops in the input; the body paragraph carries no tracked change, so its text must survive the round-trip unchanged regardless of the cyclic style definitions. refs: MS-OI29500 §2.1.233, ISO 29500-1 §17.7.4.3, ISO 29500-1 §17.7.1"
    );
}

#[test]
fn basedon_missing_target_ignored_opens_clean() {
    let styles = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><w:styles xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:style w:type="paragraph" w:styleId="Orphan"><w:name w:val="Orphan"/><w:basedOn w:val="NoSuchStyle"/><w:rPr><w:b/></w:rPr></w:style></w:styles>"#;
    let body = r#"<w:p><w:pPr><w:pStyle w:val="Orphan"/></w:pPr><w:r><w:t>orphan based-on</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[("word/styles.xml", styles)]);

    assert_opens_clean(
        &b,
        "§17.7.4.3: an unmatched basedOn shall be ignored and the style becomes a root, a non-fatal condition; a headless-Word engine must open the document without repair. refs: ISO 29500-1 §17.7.4.3, ISO 29500-1 §17.7.1",
    );

    let doc = Document::parse(&b).expect("parse");
    assert_eq!(
        doc.read_rejected().unwrap().to_text().trim(),
        "orphan based-on",
        "The body text is plain (no tracked change) and must round-trip unchanged despite the dangling basedOn reference. refs: ISO 29500-1 §17.7.4.3, ISO 29500-1 §17.7.1"
    );
}

