#[test]
fn turn_off_inherited_toggle_in_chain_reject_text_survives() {
    let styles = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><w:styles xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:style w:type="paragraph" w:styleId="BoldItalicBase"><w:name w:val="BoldItalicBase"/><w:rPr><w:b/><w:i/></w:rPr></w:style><w:style w:type="paragraph" w:styleId="ChildOff"><w:name w:val="ChildOff"/><w:basedOn w:val="BoldItalicBase"/><w:rPr><w:b w:val="0"/></w:rPr></w:style></w:styles>"#;
    let body = r#"<w:p><w:pPr><w:pStyle w:val="ChildOff"/></w:pPr><w:r><w:t>turn off inherited</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[("word/styles.xml", styles)]);

    assert_opens_clean(
        &b,
        "§17.7.1: turning OFF an inherited property and inheriting an unspecified one is a legal build-up; the document must open without repair. refs: ISO 29500-1 §17.7.1, ISO 29500-1 §17.7.4.3",
    );

    let doc = Document::parse(&b).expect("parse");
    assert_eq!(
        doc.read_rejected().unwrap().to_text().trim(),
        "turn off inherited",
        "Style toggles affect formatting only, not text content; the plain body text must round-trip unchanged. refs: ISO 29500-1 §17.7.1, ISO 29500-1 §17.7.4.3"
    );
}

