#[test]
fn basedon_self_reference_single_node_cycle_opens_clean() {
    let styles = "<?xml version=\"1.0\" encoding=\"UTF-8\" standalone=\"yes\"?>\n<w:styles xmlns:w=\"http://schemas.openxmlformats.org/wordprocessingml/2006/main\">\n  <w:style w:type=\"paragraph\" w:default=\"1\" w:styleId=\"Normal\"><w:name w:val=\"Normal\"/></w:style>\n  <w:style w:type=\"paragraph\" w:styleId=\"SelfLoop\"><w:name w:val=\"Self Loop\"/><w:basedOn w:val=\"SelfLoop\"/><w:pPr><w:ind w:left=\"720\"/></w:pPr></w:style>\n</w:styles>";
    let body = r#"<w:p><w:pPr><w:pStyle w:val="SelfLoop"/></w:pPr><w:r><w:t>self loop body</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[("word/styles.xml", styles)]);

    assert_opens_clean(
        &b,
        "Word breaks the one-node basedOn cycle and opens the document without repair (MS-OI29500 §2.1.233); stemma must terminate cycle detection and validate clean, not hang/crash/error. refs: ISO 29500-1 §17.7.4.3, MS-OI29500 §2.1.233",
    );
}

